from collections import deque
graph = {"a": ["b", "c"], "b": ["d"], "c": [], "d": []}
order, seen, q = [], {"a"}, deque(["a"])
while q:
    n = q.popleft()
    order.append(n)
    for m in graph[n]:
        if m not in seen:
            seen.add(m)
            q.append(m)
print(order)
